import React from 'react';
import { Line } from 'react-konva';

const PenTool = ({ points, strokeWidth = 2, stroke = '#000000' }) => {
  return (
    <Line
      points={points}
      stroke={stroke}
      strokeWidth={strokeWidth}
      tension={0.5}
      lineCap="round"
      lineJoin="round"
      globalCompositeOperation="source-over"
    />
  );
};

export default PenTool;
